def print_keys_with_level(d, level=1):
    """
    Recursively prints keys in a nested dictionary with their depth level.
    """
    for key, value in d.items():
        # Print the current key with appropriate indentation based on its level
        indent = "  " * (level - 1)
        print(f"{indent}Level {level}: {key}")

        # If the value is a dictionary, recurse into it, incrementing the level
        if isinstance(value, dict):
            print_keys_with_level(value, level + 1)

